const MD_DATES = {
  1: { A:"11/06",B:"12/06",C:"12/06",D:"13/06",E:"13/06",F:"14/06",G:"14/06",H:"15/06",I:"15/06",J:"11/06",K:"12/06",L:"13/06" },
  2: { A:"19/06",B:"20/06",C:"19/06",D:"21/06",E:"20/06",F:"22/06",G:"21/06",H:"23/06",I:"22/06",J:"20/06",K:"19/06",L:"21/06" },
  3: { A:"26/06",B:"26/06",C:"27/06",D:"27/06",E:"28/06",F:"28/06",G:"29/06",H:"29/06",I:"30/06",J:"30/06",K:"02/07",L:"02/07" },
};

function generateMatches() {
  const matches = [];
  let id = 1;
  Object.entries(GROUPS).forEach(([g, teams]) => {
    [
      { md:1, pairs:[[0,1],[2,3]] },
      { md:2, pairs:[[0,2],[1,3]] },
      { md:3, pairs:[[0,3],[1,2]] },
    ].forEach(({ md, pairs }) => {
      pairs.forEach(([i, j]) => {
        matches.push({ id: id++, group: `Groupe ${g}`, gKey: g, md, team1: teams[i], team2: teams[j], date: MD_DATES[md][g] });
      });
    });
  });
  return matches;
}

const ALL_MATCHES = generateMatches();

// ─── Pronos IA factices — déterministes par match ID ─
function genAIPred(matchId) {
  // Scores réalistes pondérés : favorise les petits scores
  const pool = [
    [1,0],[2,0],[2,1],[1,1],[0,0],[3,1],[3,0],[2,2],[1,2],[0,1],[0,2],[3,2],[4,1],[1,3],[0,3],[4,0]
  ];
  // Hash simple et stable basé sur l'id
  const idx = ((matchId * 2654435761) >>> 0) % pool.length;
  const [s1, s2] = pool[idx];
  return { s1, s2 };
}
const AI_PREDS = Object.fromEntries(ALL_MATCHES.map(m => [m.id, genAIPred(m.id)]));

function calcPts(pred, real) {
  if (!pred || !real) return null;
  const { s1: ps1, s2: ps2 } = pred;
  const { s1: rs1, s2: rs2 } = real;
  if (ps1 === rs1 && ps2 === rs2) return 5;
  const po = ps1 > ps2 ? 1 : ps1 < ps2 ? 2 : 0;
  const ro = rs1 > rs2 ? 1 : rs1 < rs2 ? 2 : 0;
  if (po !== ro) return 0;
  if ((ps1 - ps2) === (rs1 - rs2)) return 3;
  if (ps1 === rs1 || ps2 === rs2) return 2;
  return 1;
}

function ptsMeta(pts) {
  if (pts === 5) return { icon:"🏆", label:"Score exact",    color:"green", hex:"#15803d", bg:"rgba(21,128,61,0.12)",  border:"rgba(21,128,61,0.4)"  };
  if (pts === 3) return { icon:"🎯", label:"Bon écart",      color:"teal",  hex:"#0d9488", bg:"rgba(13,148,136,0.12)", border:"rgba(13,148,136,0.4)" };
  if (pts === 2) return { icon:"⚡", label:"Buts partiels",  color:"blue",  hex:"#1d4ed8", bg:"rgba(29,78,216,0.10)",  border:"rgba(29,78,216,0.35)" };
  if (pts === 1) return { icon:"✔",  label:"Bon résultat",   color:"gold",  hex:"#b45309", bg:"rgba(180,83,9,0.10)",   border:"rgba(180,83,9,0.35)"  };
  if (pts === 0) return { icon:"❌", label:"Raté",            color:"red",   hex:"#dc2626", bg:"rgba(220,38,38,0.10)",  border:"rgba(220,38,38,0.35)" };
  return null;
}

const medalEmoji = (i) => i===0?"🥇":i===1?"🥈":i===2?"🥉":null;

// Sépare le drapeau du nom : "🇫🇷 France" → { flag:"🇫🇷", name:"France" }
const splitTeam = (t) => {
  const parts = t.split(" ");
  // Les drapeaux emoji font 1 codepoint graphème (parfois 2 chars UTF-16)
  // On prend tout jusqu'au premier segment "texte" comme flag
  const nameIdx = parts.findIndex(p => !/\p{Emoji}/u.test(p));
  if (nameIdx <= 0) return { flag: parts[0], name: parts.slice(1).join(" ") };
  return { flag: parts.slice(0, nameIdx).join(""), name: parts.slice(nameIdx).join(" ") };
};

